		return
	}

	// Close the request body to avoid leaking resources
	defer r.Body.Close()

	// Print the request content
	fmt.Println("Request Content:", string(body))

	// Respond with a success message
	w.WriteHeader(http.StatusOK)
	fmt.Fprintf(w, "Request content received and printed successfully")
}

func main() {
	// Set up the server to listen on port 8080
	http.HandleFunc("/", handler)
	http.ListenAndServe(":8080", nil)
}
